// tlShadowMeshChunk

int tlShadowMeshChunk::sortPriority = -1;

tlShadowMeshChunk::tlShadowMeshChunk()
{
    Init();
}

tlShadowMeshChunk::tlShadowMeshChunk(const tlShadowMeshChunk& ch)
{
    Init();
    *this = ch;
}

tlShadowMeshChunk::~tlShadowMeshChunk()
{

    if(name != NULL){
        strdelete(name);
    }
}

tlShadowMeshChunk::tlShadowMeshChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Mesh::SHADOWMESH);
    ident = Pure3D::Mesh::SHADOWMESH;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    name = strnew(buf);
    version = f->GetLong();
    numvertices = f->GetLong();
    numtriangles = f->GetLong();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Mesh::SHADOWMESH);
    }
}

void
tlShadowMeshChunk::Init()
{
    ident = Pure3D::Mesh::SHADOWMESH;
    name = NULL;
    version = 0;
    numvertices = 0;
    numtriangles = 0;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Mesh::SHADOWMESH);
    }
}

long 
tlShadowMeshChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += strlen( name );
    s += sizeof( version );
    s += sizeof( numvertices );
    s += sizeof( numtriangles );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlShadowMeshChunk&
tlShadowMeshChunk::operator=(const tlShadowMeshChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    name = strnew(a.name);
    version = a.version;
    numvertices = a.numvertices;
    numtriangles = a.numtriangles;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlShadowMeshChunk::operator==(const tlDataChunk& a)
{

    const tlShadowMeshChunk* aptr = dynamic_cast<const tlShadowMeshChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(version == aptr->version))
    {
        return false;
    }
    if(!(numvertices == aptr->numvertices))
    {
        return false;
    }
    if(!(numtriangles == aptr->numtriangles))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlShadowMeshChunk::NameCompare(const tlDataChunk& a)
{

    const tlShadowMeshChunk* aptr = dynamic_cast<const tlShadowMeshChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }

    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    return true;
}


tlDataChunk*
tlShadowMeshChunk::Create(tlReadChunk16* ch)
{
    tlDataChunk* dtCh = new tlShadowMeshChunk(ch);
    return dtCh;
}

void
tlShadowMeshChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutPString(name);
        f->PutLong(version);
        f->PutLong(numvertices);
        f->PutLong(numtriangles);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlShadowMeshChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlShadowMeshChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  Name         = \"%s\"\n",indent,"",name);
    printf("%*s  Version      = %ld\n",indent,"",version);
    printf("%*s  NumVertices  = %ld\n",indent,"",numvertices);
    printf("%*s  NumTriangles = %ld\n",indent,"",numtriangles);

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlShadowMeshChunk::PrintFormatted(int indent)
{
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  pstring \"%s\" # Name        \n",indent,"",name);
    printf("%*s  int   %12ld # Version     \n",indent,"",version);
    printf("%*s  int   %12ld # NumVertices \n",indent,"",numvertices);
    printf("%*s  int   %12ld # NumTriangles\n",indent,"",numtriangles);
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

